import { useState } from "react";
import { Link } from "react-router-dom";
import Button from "../components/Button";
import { useCart } from "../context/CartContext";

const paymentModes = ["Card", "UPI", "Cash on Delivery"];

function CheckoutPage() {
  const { cartItems, subtotal, clearCart } = useCart();
  const [paymentMode, setPaymentMode] = useState("Card");
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    phone: "",
    address: "",
    city: "",
    state: "",
    zipCode: "",
  });

  if (cartItems.length === 0 && !orderPlaced) {
    return (
      <div className="mx-auto max-w-7xl px-4 py-16 sm:px-6 lg:px-8">
        <div className="rounded-xl border border-slate-100 bg-white p-8 text-center shadow-md">
          <h1 className="text-2xl font-bold text-slate-900">No Items to Checkout</h1>
          <p className="mt-2 text-slate-500">Your cart is empty right now.</p>
          <Link
            className="mt-6 inline-flex rounded-xl bg-primary-600 px-5 py-2.5 text-sm font-semibold text-white"
            to="/shop"
          >
            Go to Shop
          </Link>
        </div>
      </div>
    );
  }

  const shipping = subtotal >= 200 ? 0 : 14.99;
  const total = subtotal + shipping;

  const handleFormChange = (event) => {
    const { name, value } = event.target;
    setFormData((currentData) => ({
      ...currentData,
      [name]: value,
    }));
  };

  const handlePlaceOrder = (event) => {
    event.preventDefault();
    setOrderPlaced(true);
    clearCart();
  };

  if (orderPlaced) {
    return (
      <div className="mx-auto max-w-7xl px-4 py-16 sm:px-6 lg:px-8">
        <div className="rounded-xl border border-primary-100 bg-primary-50 p-8 text-center shadow-md">
          <h1 className="text-2xl font-bold text-slate-900">Order Placed Successfully</h1>
          <p className="mt-2 text-slate-600">
            Thanks for your purchase. A confirmation has been sent to your email.
          </p>
          <Link
            className="mt-6 inline-flex rounded-xl bg-primary-600 px-5 py-2.5 text-sm font-semibold text-white"
            to="/shop"
          >
            Continue Shopping
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">
      <h1 className="mb-6 text-2xl font-bold text-slate-900">Checkout</h1>
      <div className="grid gap-6 lg:grid-cols-[1.6fr_1fr]">
        <form
          className="space-y-6 rounded-xl border border-slate-100 bg-white p-6 shadow-md"
          onSubmit={handlePlaceOrder}
        >
          <section>
            <h2 className="text-lg font-bold text-slate-900">Shipping Address</h2>
            <div className="mt-4 grid gap-4 sm:grid-cols-2">
              <InputField
                label="Full Name"
                name="fullName"
                onChange={handleFormChange}
                required
                value={formData.fullName}
              />
              <InputField
                label="Email"
                name="email"
                onChange={handleFormChange}
                required
                type="email"
                value={formData.email}
              />
              <InputField
                label="Phone Number"
                name="phone"
                onChange={handleFormChange}
                required
                value={formData.phone}
              />
              <InputField
                label="City"
                name="city"
                onChange={handleFormChange}
                required
                value={formData.city}
              />
              <InputField
                className="sm:col-span-2"
                label="Address"
                name="address"
                onChange={handleFormChange}
                required
                value={formData.address}
              />
              <InputField
                label="State"
                name="state"
                onChange={handleFormChange}
                required
                value={formData.state}
              />
              <InputField
                label="ZIP Code"
                name="zipCode"
                onChange={handleFormChange}
                required
                value={formData.zipCode}
              />
            </div>
          </section>

          <section>
            <h2 className="text-lg font-bold text-slate-900">Payment Method</h2>
            <div className="mt-4 grid gap-3 sm:grid-cols-3">
              {paymentModes.map((mode) => (
                <label
                  className={`cursor-pointer rounded-xl border p-4 text-sm font-semibold transition ${
                    paymentMode === mode
                      ? "border-primary-500 bg-primary-50 text-primary-700"
                      : "border-slate-200 text-slate-600 hover:bg-slate-50"
                  }`}
                  key={mode}
                >
                  <input
                    checked={paymentMode === mode}
                    className="sr-only"
                    name="paymentMode"
                    onChange={() => setPaymentMode(mode)}
                    type="radio"
                  />
                  {mode}
                </label>
              ))}
            </div>
          </section>

          <Button className="w-full sm:w-auto" type="submit" variant="primary">
            Place Order
          </Button>
        </form>

        <aside className="h-fit rounded-xl border border-slate-100 bg-white p-6 shadow-md">
          <h2 className="text-lg font-bold text-slate-900">Order Summary</h2>
          <div className="mt-4 space-y-3">
            {cartItems.map((item) => (
              <div
                className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-2 text-sm"
                key={item.id}
              >
                <p className="max-w-[70%] truncate text-slate-700">
                  {item.title} x {item.quantity}
                </p>
                <p className="font-semibold text-slate-900">
                  ${(item.price * item.quantity).toFixed(2)}
                </p>
              </div>
            ))}
          </div>

          <dl className="mt-6 space-y-3 text-sm">
            <div className="flex items-center justify-between text-slate-600">
              <dt>Subtotal</dt>
              <dd>${subtotal.toFixed(2)}</dd>
            </div>
            <div className="flex items-center justify-between text-slate-600">
              <dt>Shipping</dt>
              <dd>{shipping === 0 ? "Free" : `$${shipping.toFixed(2)}`}</dd>
            </div>
            <div className="flex items-center justify-between border-t border-slate-100 pt-3 text-base font-bold text-slate-900">
              <dt>Total</dt>
              <dd>${total.toFixed(2)}</dd>
            </div>
          </dl>
        </aside>
      </div>
    </div>
  );
}

function InputField({
  className = "",
  label,
  name,
  onChange,
  required = false,
  type = "text",
  value,
}) {
  return (
    <label className={`block ${className}`.trim()}>
      <span className="mb-1 block text-sm font-medium text-slate-700">{label}</span>
      <input
        className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-700 focus:border-primary-500 focus:outline-none"
        name={name}
        onChange={onChange}
        required={required}
        type={type}
        value={value}
      />
    </label>
  );
}

export default CheckoutPage;
